以下代码的输出是什么？

```go
func modify(s ...int) {
    s[0] = 100
}

func main() {
    a := []int{1, 2, 3}
    modify(a...)
    fmt.Println(a)
}
```

以下代码有什么问题？

```go
func merge(slices ...[]int) []int {
    var result []int
    for _, s := range slices {
        result = append(result, s...)
    }
    return result
}

func main() {
    a := []int{1, 2, 3, 4, 5}
    b := a[:3]
    c := a[2:]
    merged := merge(b, c)
    merged[0] = 999
    fmt.Println(a)
}
```

